import React, { useEffect, useState } from 'react';
import type { AdminSectionProps } from '../types';
import { TradeApiClient } from '../../utils/apiClient';

export function OverviewPanel({ pluginContext }: AdminSectionProps) {
  const [stats, setStats] = useState<any>(null);
  const [health, setHealth] = useState<any>(null);

  useEffect(() => {
    const api = new TradeApiClient(pluginContext.serverUrl, pluginContext.getAccessToken);
    api.getHealth().then(setHealth).catch(() => {});
    fetch(`${pluginContext.serverUrl}/admin/stats`, {
      headers: { 'Authorization': `Bearer ${pluginContext.getAccessToken()}` },
    }).then(r => r.json()).then(setStats).catch(() => {});
  }, [pluginContext]);

  return (
    <div className="ct-space-y-6">
      <h2 className="ct-text-xl ct-font-semibold">Trade Overview</h2>
      <div className="ct-grid ct-grid-cols-2 lg:ct-grid-cols-4 ct-gap-4">
        <StatCard label="Total Quotes" value={stats?.totalQuotes ?? 0} />
        <StatCard label="Total Swaps" value={stats?.totalSwaps ?? 0} />
        <StatCard label="Cache Hit Ratio" value={`${((stats?.cacheHitRatio ?? 0) * 100).toFixed(1)}%`} />
        <StatCard label="Service Status" value={health?.status ?? 'unknown'} />
      </div>
      {stats?.executions && (
        <div className="ct-grid ct-grid-cols-2 ct-gap-4">
          <StatCard label="Executions Succeeded" value={stats.executions.succeeded} />
          <StatCard label="Executions Failed" value={stats.executions.failed} />
        </div>
      )}
    </div>
  );
}

function StatCard({ label, value }: { label: string; value: string | number }) {
  return (
    <div className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4">
      <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">{label}</div>
      <div className="ct-text-2xl ct-font-bold ct-text-[hsl(var(--cedros-foreground))]">{value}</div>
    </div>
  );
}
